/* Test driver */
public class Main {
    public static void main(String[] args) {
        ParkingLot lot = ParkingLot.getInstance();
        lot.addLevel(0, 1, 0);
        Ticket t = lot.parkVehicle(new Car("AB-9"));
        if (t == null) { System.out.println("FAIL: park"); System.exit(1); }
        double fee = lot.unparkVehicle(t.getTicketId());
        if (fee < 0) { System.out.println("FAIL: unpark"); System.exit(1); }
        Ticket t2 = lot.parkVehicle(new Car("AB-10"));
        System.out.println(t2 != null ? "REPARK_OK" : "REPARK_FAIL");
    }
}

